<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Personal Expense Tracker</title>
<style>
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif; background: #f4f6f8; color: #222; padding: 20px; max-width: 800px; margin: 0 auto; }
  h1 { text-align: center; margin-bottom: 20px; font-size: 1.6rem; }
  h2 { font-size: 1.1rem; margin-bottom: 10px; border-bottom: 1px solid #ccc; padding-bottom: 4px; }
  section { background: #fff; border-radius: 8px; padding: 16px; margin-bottom: 16px; box-shadow: 0 1px 3px rgba(0,0,0,.1); }
  label { display: block; font-weight: 600; margin-bottom: 4px; font-size: .9rem; }
  input, select { width: 100%; padding: 8px 10px; border: 1px solid #bbb; border-radius: 4px; font-size: .95rem; margin-bottom: 10px; }
  input:focus, select:focus { outline: none; border-color: #4a90d9; box-shadow: 0 0 0 2px rgba(74,144,217,.25); }
  button { cursor: pointer; border: none; border-radius: 4px; font-size: .95rem; padding: 8px 16px; }
  #add-expense { background: #4a90d9; color: #fff; width: 100%; padding: 10px; font-weight: 600; }
  #add-expense:hover { background: #3a7bc8; }
  #form-error { color: #c0392b; font-size: .85rem; min-height: 1.2em; margin-bottom: 6px; }
  .expense { display: flex; align-items: center; justify-content: space-between; padding: 10px 12px; border-bottom: 1px solid #eee; gap: 8px; }
  .expense:last-child { border-bottom: none; }
  .expense .info { flex: 1; min-width: 0; }
  .expense .info .amount { font-weight: 700; font-size: 1rem; }
  .expense .info .meta { font-size: .82rem; color: #666; }
  .expense .info .note { font-size: .82rem; color: #888; font-style: italic; }
  .exp-del { background: #e74c3c; color: #fff; padding: 5px 10px; font-size: .8rem; white-space: nowrap; }
  .exp-del:hover { background: #c0392b; }
  .filters { display: flex; gap: 10px; flex-wrap: wrap; }
  .filters > div { flex: 1; min-width: 140px; }
  #total { font-size: 1.3rem; font-weight: 700; text-align: center; padding: 10px; }
  .cat-summary { display: flex; flex-wrap: wrap; gap: 10px; }
  .cat-total { background: #eaf2fb; border-radius: 6px; padding: 8px 14px; font-size: .9rem; font-weight: 600; }
  .empty-msg { text-align: center; color: #999; padding: 20px; font-size: .9rem; }
</style>
</head>
<body>

<h1>💰 Expense Tracker</h1>

<!-- Entry Form -->
<section>
  <h2>Add Expense</h2>
  <form id="expense-form" novalidate>
    <label for="amount">Amount</label>
    <input type="number" id="amount" step="0.01" placeholder="0.00">

    <label for="category">Category</label>
    <select id="category">
      <option value="groceries">groceries</option>
      <option value="transport">transport</option>
      <option value="bills">bills</option>
      <option value="fun">fun</option>
    </select>

    <label for="date">Date</label>
    <input type="date" id="date">

    <label for="note">Note (optional)</label>
    <input type="text" id="note" placeholder="What was it for?">

    <div id="form-error"></div>
    <button type="submit" id="add-expense">Add Expense</button>
  </form>
</section>

<!-- Filters -->
<section>
  <h2>Filters</h2>
  <div class="filters">
    <div>
      <label for="filter-category">Category</label>
      <select id="filter-category">
        <option value="all">all</option>
        <option value="groceries">groceries</option>
        <option value="transport">transport</option>
        <option value="bills">bills</option>
        <option value="fun">fun</option>
      </select>
    </div>
    <div>
      <label for="filter-from">From</label>
      <input type="date" id="filter-from">
    </div>
    <div>
      <label for="filter-to">To</label>
      <input type="date" id="filter-to">
    </div>
  </div>
</section>

<!-- Total -->
<section>
  <h2>Total (Visible)</h2>
  <div id="total">0.00</div>
</section>

<!-- Category Summary -->
<section>
  <h2>Category Breakdown</h2>
  <div class="cat-summary" id="cat-summary"></div>
</section>

<!-- Expense List -->
<section>
  <h2>Expenses</h2>
  <div id="expense-list"></div>
</section>

<script>
(function() {
  const STORAGE_KEY = 'expense_tracker_data';
  const categories = ['groceries', 'transport', 'bills', 'fun'];

  // DOM refs
  const form = document.getElementById('expense-form');
  const amountInput = document.getElementById('amount');
  const categoryInput = document.getElementById('category');
  const dateInput = document.getElementById('date');
  const noteInput = document.getElementById('note');
  const formError = document.getElementById('form-error');
  const addBtn = document.getElementById('add-expense');
  const expenseList = document.getElementById('expense-list');
  const totalEl = document.getElementById('total');
  const catSummaryEl = document.getElementById('cat-summary');
  const filterCategory = document.getElementById('filter-category');
  const filterFrom = document.getElementById('filter-from');
  const filterTo = document.getElementById('filter-to');

  // Load expenses from localStorage
  let expenses = [];
  try {
    const stored = localStorage.getItem(STORAGE_KEY);
    if (stored) expenses = JSON.parse(stored);
  } catch(e) {
    expenses = [];
  }

  function save() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
  }

  function validate() {
    const amt = amountInput.value.trim();
    const dt = dateInput.value.trim();

    if (!dt) {
      formError.textContent = 'Please select a date.';
      return false;
    }
    if (amt === '' || isNaN(Number(amt)) || Number(amt) <= 0) {
      formError.textContent = 'Please enter a valid positive amount.';
      return false;
    }
    return true;
  }

  form.addEventListener('submit', function(e) {
    e.preventDefault();
    if (!validate()) return;

    const expense = {
      id: Date.now() + Math.random(),
      amount: parseFloat(parseFloat(amountInput.value).toFixed(2)),
      category: categoryInput.value,
      date: dateInput.value,
      note: noteInput.value.trim()
    };

    expenses.push(expense);
    save();
    formError.textContent = '';
    amountInput.value = '';
    noteInput.value = '';
    render();
  });

  // Delete handler
  expenseList.addEventListener('click', function(e) {
    if (e.target.classList.contains('exp-del')) {
      const id = parseFloat(e.target.dataset.id);
      expenses = expenses.filter(function(exp) { return exp.id !== id; });
      save();
      render();
    }
  });

  // Filter change handlers
  filterCategory.addEventListener('change', render);
  filterFrom.addEventListener('change', render);
  filterTo.addEventListener('change', render);

  function getFiltered() {
    const catFilter = filterCategory.value;
    const fromVal = filterFrom.value;
    const toVal = filterTo.value;

    return expenses.filter(function(exp) {
      if (catFilter !== 'all' && exp.category !== catFilter) return false;
      if (fromVal && exp.date < fromVal) return false;
      if (toVal && exp.date > toVal) return false;
      return true;
    });
  }

  function render() {
    const filtered = getFiltered();

    // Sort newest first
    filtered.sort(function(a, b) {
      if (b.date !== a.date) return b.date.localeCompare(a.date);
      return b.id - a.id;
    });

    // Render list
    expenseList.innerHTML = '';
    if (filtered.length === 0) {
      expenseList.innerHTML = '<div class="empty-msg">No expenses to show.</div>';
    } else {
      filtered.forEach(function(exp) {
        const row = document.createElement('div');
        row.className = 'expense';
        row.innerHTML =
          '<div class="info">' +
            '<span class="amount">$' + exp.amount.toFixed(2) + '</span> ' +
            '<span class="meta">[' + exp.category + '] ' + exp.date + '</span>' +
            (exp.note ? '<div class="note">' + escapeHtml(exp.note) + '</div>' : '') +
          '</div>' +
          '<button class="exp-del" data-id="' + exp.id + '">Delete</button>';
        expenseList.appendChild(row);
      });
    }

    // Calculate total of visible expenses
    const total = filtered.reduce(function(sum, exp) { return sum + exp.amount; }, 0);
    totalEl.textContent = total.toFixed(2);

    // Category summary for visible expenses
    const catTotals = {};
    categories.forEach(function(c) { catTotals[c] = 0; });
    filtered.forEach(function(exp) {
      if (catTotals.hasOwnProperty(exp.category)) {
        catTotals[exp.category] += exp.amount;
      }
    });

    catSummaryEl.innerHTML = '';
    categories.forEach(function(cat) {
      const el = document.createElement('div');
      el.className = 'cat-total';
      el.setAttribute('data-cat', cat);
      el.textContent = cat + ': $' + catTotals[cat].toFixed(2);
      catSummaryEl.appendChild(el);
    });
  }

  function escapeHtml(str) {
    const div = document.createElement('div');
    div.textContent = str;
    return div.innerHTML;
  }

  // Initial render
  render();
})();
</script>

</body>
</html>
